// This is your Prisma schema file,
// learn more about it in the docs: https://pris.ly/d/prisma-schema

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model Racquet {
  id    Int    @id @default(autoincrement())
  code  String @unique
  model String
  brand String

  // Physical specifications
  weightOz      Float?
  lengthIn      Float?
  headSizeSqIn  Int?
  balanceIn     Float?
  flexRating    Int?
  swingweight   Int?
  stringPattern String?
  construction  String?
  material      String?

  // Performance averages (computed from reviews)
  powerAvg          Float?
  controlAvg        Float?
  comfortAvg        Float?
  maneuverabilityAvg Float?
  stabilityAvg      Float?

  // Metadata
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  // Relations
  reviews Review[]

  @@map("racquets")
}

model Review {
  id           Int      @id @default(autoincrement())
  racquetId    Int
  playerName   String
  category     String
  score        Float
  createdAt    DateTime @default(now())

  // Relations
  racquet Racquet @relation(fields: [racquetId], references: [id], onDelete: Cascade)

  @@map("reviews")
}

