import { PrismaClient } from '@prisma/client'
import { readFileSync } from 'fs'
import { join } from 'path'

const prisma = new PrismaClient()

interface RacquetData {
  id: string
  code: string
  model: string
  brand: string
  flex: number
  swingweight: number
  length: string
  head_size: string
  weight: string
  balance: string
  construction: string
  material: string
  string_pattern: string
}

interface ReviewData {
  player: string
  category: string
  score: number
  model: string
  code: string
  brand: string
  flex: number
  swingweight: number
  length: string
  head_size: string
  weight: string
  balance: string
  construction: string
  material: string
  string_pattern: string
}

function parseWeight(weightStr: string): number | null {
  if (!weightStr) return null
  const match = weightStr.match(/(\d+\.?\d*)/);
  return match ? parseFloat(match[1]) : null;
}

function parseLength(lengthStr: string): number | null {
  if (!lengthStr) return null
  const match = lengthStr.match(/(\d+\.?\d*)/);
  return match ? parseFloat(match[1]) : null;
}

function parseHeadSize(headSizeStr: string): number | null {
  if (!headSizeStr) return null
  const match = headSizeStr.match(/(\d+)/);
  return match ? parseInt(match[1]) : null;
}

function parseBalance(balanceStr: string): number | null {
  if (!balanceStr) return null
  const match = balanceStr.match(/(\d+\.?\d*)/);
  return match ? parseFloat(match[1]) : null;
}

async function main() {
  console.log('🎾 Starting data migration...')

  try {
    // Read data files
    const racquetsPath = join(process.cwd(), 'src/data/racquets.json')
    const reviewsPath = join(process.cwd(), 'src/data/reviews.json')

    const racquetsData: RacquetData[] = JSON.parse(readFileSync(racquetsPath, 'utf-8'))
    const reviewsData: ReviewData[] = JSON.parse(readFileSync(reviewsPath, 'utf-8'))

    console.log(`📊 Found ${racquetsData.length} racquets and ${reviewsData.length} reviews`)

    // Clear existing data
    console.log('🧹 Clearing existing data...')
    await prisma.review.deleteMany()
    await prisma.racquet.deleteMany()

    // Insert racquets
    console.log('🎾 Inserting racquets...')
    for (const racquet of racquetsData) {
      // Calculate average performance scores for this racquet
      const racquetReviews = reviewsData.filter(review => review.code === racquet.code)

      const performanceCategories = ['Power', 'Control', 'Comfort', 'Maneuverability', 'Stability']
      const averages: { [key: string]: number } = {}

      for (const category of performanceCategories) {
        const categoryReviews = racquetReviews.filter(review => 
          review.category.toLowerCase() === category.toLowerCase()
        )
        if (categoryReviews.length > 0) {
          const sum = categoryReviews.reduce((acc, review) => acc + review.score, 0)
          averages[category.toLowerCase()] = sum / categoryReviews.length
        }
      }

      await prisma.racquet.create({
        data: {
          code: racquet.code,
          model: racquet.model,
          brand: racquet.brand,
          weightOz: parseWeight(racquet.weight),
          lengthIn: parseLength(racquet.length),
          headSizeSqIn: parseHeadSize(racquet.head_size),
          balanceIn: parseBalance(racquet.balance),
          flexRating: racquet.flex || null,
          swingweight: racquet.swingweight || null,
          stringPattern: racquet.string_pattern || null,
          construction: racquet.construction || null,
          material: racquet.material || null,
          powerAvg: averages.power || null,
          controlAvg: averages.control || null,
          comfortAvg: averages.comfort || null,
          maneuverabilityAvg: averages.maneuverability || null,
          stabilityAvg: averages.stability || null,
        },
      })
    }

    // Insert reviews
    console.log('📝 Inserting reviews...')
    for (const review of reviewsData) {
      // Find the racquet ID
      const racquet = await prisma.racquet.findUnique({
        where: { code: review.code }
      })

      if (racquet) {
        await prisma.review.create({
          data: {
            racquetId: racquet.id,
            playerName: review.player,
            category: review.category,
            score: review.score,
          },
        })
      }
    }

    const finalRacquetCount = await prisma.racquet.count()
    const finalReviewCount = await prisma.review.count()

    console.log(`✅ Migration completed successfully!`)
    console.log(`🎾 Inserted ${finalRacquetCount} racquets`)
    console.log(`📝 Inserted ${finalReviewCount} reviews`)

  } catch (error) {
    console.error('❌ Migration failed:', error)
    process.exit(1)
  } finally {
    await prisma.$disconnect()
  }
}

main()

