import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

async function testConnection() {
  try {
    console.log('🔍 Testing database connection...')

    // Test basic connection
    await prisma.$connect()
    console.log('✅ Database connection successful')

    // Test if tables exist (this will only work after migration)
    try {
      const racquetCount = await prisma.racquet.count()
      const reviewCount = await prisma.review.count()
      console.log(`📊 Found ${racquetCount} racquets and ${reviewCount} reviews`)
    } catch (error) {
      console.log('ℹ️  Database tables not yet created (run migration first)')
    }

  } catch (error) {
    console.error('❌ Database connection failed:', error)
    console.log('💡 Make sure PostgreSQL is running and DATABASE_URL is correct in .env')
  } finally {
    await prisma.$disconnect()
  }
}

testConnection()

